mapper.select:
select pss.production_stats_id, pss.avg_output_per_person, pss.order_delivery_days, pss.planned_daily_output, pss.price_per_unit, pss.time_per_person, pss.use_date, pss.people_number, pss.work_time, pss.dep_id, pss.product_id, dt.dep_name, pt.product_style_name, pt.product_name from production_stats pss inner join department dt on dt.dep_id = pss.dep_id and dt.delete_flg = false inner join product pt on pt.product_id = pss.product_id and pt.delete_flg = false where pss.delete_flg = false
AND pss.product_id = #{productId,jdbcType=INTEGER}
AND pss.dep_id = #{depId,jdbcType=INTEGER}
and pss.use_date = CAST(#{useDate} AS DATE)
order by pss.dep_id, pss.use_date
